"    // Inject glow paths & outlines into DOM
    glowSvgLayer.innerHTML = Object.keys(WORLD_MAP_GLOW_PATHS).map(region => `
        <path class="map-region-glow" data-region="${region}" fill="none" d="" />
    `).join('');

    outlinesGroup.innerHTML = Object.keys(WORLD_MAP_PATHS).map(region => `
        <path class="map-outline-line" data-region="${region}" fill="none" d="" />
    `).join('');

    // Generate dot DOM elements
    dotsGroup.innerHTML = dots.map((dot, index) => {
        return `
            <circle class="map-dot" data-region="${dot.region}" data-index="${index}" cx="0" cy="0" r="1.5"
                    style="display: none; fill: ${dot.color}; transform-style: preserve-3d;" />
        `;
    }).join('');

    // Cache DOM elements and dot objects for high performance loop
    const dotElementsAndData = [];
    const dotEls = dotsGroup.querySelectorAll('.map-dot');
    dotEls.forEach((el, idx) => {
        dotElementsAndData.push({
            el: el,
            dot: dots[idx]
        });
    });

