    let isDragging = false;
    let lastMouseX = 0, lastMouseY = 0;

    // Default initial rotation angles (in radians) to show beautiful view
    let rotX = 0.3; // Latitude tilt (North)
    let rotY = 0.5; // Longitude spin (Atlantic/Eurasia centered)

